// The per-file [`BoundProgram`] view that owns `decl` (a signature's
// declaration node). In a multi-file program `program.arena()` is only the
// file currently being checked; signatures from another file (lib, interface
// in a sibling module) store that file's local `NodeId` and must be read
// through its declaring view — same pattern as `get_type_of_symbol`.
// Go: internal/checker/relater.go:Checker.compareSignaturesRelated (strictVariance)
fn program_for_signature_declaration<'a>(
    &self,
    program: &'a dyn BoundProgram,
    sig: SignatureId,
) -> &'a dyn BoundProgram {
    let signature = self.signature(sig);
    let Some(decl) = signature.declaration else {
        return program;
    };
    for &sym in signature
        .parameters
        .iter()
        .chain(signature.this_parameter.iter())
    {
        if let Some(view) = program.view_for_symbol(sym) {
            return view.as_ref();
        }
    }
    // Parameter-less signatures (e.g. `foo(): void`): find the file whose
    // arena owns `decl`.
    for &file in program.source_files() {
        if let Some(view) = program.file_view(file) {
            if decl.index() < view.arena().node_count() && view.symbol_of_node(decl).is_some()
            {
                return view.as_ref();
            }
        }
    }
    program
}

