// C-A: `signature_is_method` must read the target signature's declaration node
// through the declaring file's arena. A class in file B that `implements` an
// interface declared in file A triggers `compare_signatures_related` with target
// signatures whose `declaration` is a file-A `NodeId`; indexing that id through
// file B's arena panics (index out of bounds).
// Go: internal/checker/relater.go:Checker.compareSignaturesRelated (method bivariance)
#[test]
fn signature_is_method_resolves_cross_file_declaration_arena() {
    let p = std::rc::Rc::new(MultiFileProgram::build(&[
        ("/iface.ts", "interface I { m(x: number): void; }"),
        (
            "/impl.ts",
            "class C implements I { m(x: number | string) {} }",
        ),
    ]));
    let file_impl = p.source_files()[1];
    let mut c = Checker::new_checker(p);
    let diags = c.get_diagnostics(file_impl);
    assert!(
        diags.is_empty(),
        "cross-file method signature compare must not panic; expected no diagnostics, got {diags:?}"
    );
}

